mapper.select:
select id, scheme_version_id, trigger_code, object_type_code, object_id, rule_id, rule_code, rule_type, matched_flag, blocking_flag, effect_json, message, severity, skipped_reason, created_by, created_at from am_archive_rule_trace where 1 = 1
and scheme_version_id = #{criteria.schemeVersionId}
and trigger_code = #{criteria.triggerCode}
and object_type_code = #{criteria.objectTypeCode}
and object_id = #{criteria.objectId}
and rule_type = #{criteria.ruleType}
order by created_at desc, id desc limit #{criteria.limit}
